mapper.select:
select

from biz_open_claim a  left join sys_dept b on a.deptid = b.id   left join sys_user d on a.claimer = d.account left join biz_wx_user c on a.openid = c.openid

    a.status != 5

        and (a.phone like  CONCAT('%',#{condition},'%') or a.name like  CONCAT('%',#{condition},'%') or a.cph like  CONCAT('%',#{condition},'%') or a.cjh like  CONCAT('%',#{condition},'%'))


        and (a.createtime between CONCAT(#{createStartTime},' 00:00:00') and CONCAT(#{createEndTime},' 23:59:59'))


        and a.openid = #{openClaim.openid}


        and a.claimer = #{openClaim.claimer}


        and a.deptid = #{openClaim.deptid}


        and a.orderno = #{openClaim.orderno}





        and a.status = #{openClaim.status}


        and a.cph is null


        and a.cph is not null


ORDER BY a.createTime desc

