select
sum(fixloss)
from biz_open_claim a left join biz_wx_user c on a.openid = c.openid left join sys_dept b on a.deptid = b.id


        and (a.phone like  CONCAT('%',#{condition},'%') or a.name like  CONCAT('%',#{condition},'%') or a.cph like  CONCAT('%',#{condition},'%') or a.cjh like  CONCAT('%',#{condition},'%'))


