        and a.openid = #{openClaim.openid}


        and a.deptid = #{openClaim.deptid}


        and a.orderno = #{openClaim.orderno}


        and a.status = #{openClaim.status}


        and a.cph is null


        and a.cph is not null

select
count(1)
from biz_open_claim

    status != 5

        and (createtime between CONCAT(#{createStartTime},' 00:00:00') and CONCAT(#{createEndTime},' 23:59:59'))


        and openid = #{openClaim.openid}


        and deptid = #{openClaim.deptid}


        and orderno = #{openClaim.orderno}


        and status = #{openClaim.status}


        and claimer = #{openClaim.claimer}



        and cph is null


        and cph is not null

  select  cast(
sum(t1.fixloss) AS DECIMAL (19, 2)
)  from biz_open_claim t1 where to_days(t1.createTime) = to_days(now())
